const newItems = [];

for (const item of $input.all()) {
  // 1. On récupère les deux valeurs
  const q1 = item.json["Questions"];
  const q2 = item.json["Questions (Précis)"];

  // 2. Si la première question existe, on crée un item
  if (q1 && q1.trim() !== "") {
    newItems.push({
      json: { query: q1.trim(), type: "Générale" }
    });
  }

  // 3. Si la deuxième question existe, on crée un deuxième item
  if (q2 && q2.trim() !== "") {
    newItems.push({
      json: { query: q2.trim(), type: "Précise" }
    });
  }
}

// On retourne la nouvelle liste qui contient maintenant TOUTES les questions séparées
return newItems;
